package org.apache.commons.csv;
import static org.apache.commons.csv.Constants.BACKSLASH;
import static org.apache.commons.csv.Constants.COMMA;
import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.CRLF;
import static org.apache.commons.csv.Constants.DOUBLE_QUOTE_CHAR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.TAB;
import java.io.IOException;
import java.io.Reader;
import java.io.Serializable;
import java.io.StringWriter;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Method;

public class CSVFormatTest {

    @Test
    void testIsLineBreak_withNullCharacter() throws Exception {
        Method isLineBreakMethod = CSVFormat.class.getDeclaredMethod("isLineBreak", Character.class);
        isLineBreakMethod.setAccessible(true);
        Boolean result = (Boolean) isLineBreakMethod.invoke(null, (Character) null);
        assertFalse(result);
    }

    @Test
    void testIsLineBreak_withLineBreakCharacters() throws Exception {
        Method isLineBreakMethod = CSVFormat.class.getDeclaredMethod("isLineBreak", Character.class);
        isLineBreakMethod.setAccessible(true);

        // CR (carriage return)
        Boolean resultCR = (Boolean) isLineBreakMethod.invoke(null, '\r');
        assertTrue(resultCR);

        // LF (line feed)
        Boolean resultLF = (Boolean) isLineBreakMethod.invoke(null, '\n');
        assertTrue(resultLF);
    }

    @Test
    void testIsLineBreak_withNonLineBreakCharacter() throws Exception {
        Method isLineBreakMethod = CSVFormat.class.getDeclaredMethod("isLineBreak", Character.class);
        isLineBreakMethod.setAccessible(true);

        // Comma is not a line break
        Boolean result = (Boolean) isLineBreakMethod.invoke(null, ',');
        assertFalse(result);

        // Letter 'a' is not a line break
        Boolean resultA = (Boolean) isLineBreakMethod.invoke(null, 'a');
        assertFalse(resultA);
    }
}
